import { afterEach, beforeEach, describe, expect, it } from "bun:test";
import * as fs from "node:fs/promises";
import * as os from "node:os";
import * as path from "node:path";
import type { AgentToolResult } from "@amaze/agent-core";
import { Settings } from "@amaze/coding-agent/config/settings";
import type { ToolSession } from "@amaze/coding-agent/tools";
import type { ReadToolDetails } from "@amaze/coding-agent/tools/read";
import { ReadTool } from "@amaze/coding-agent/tools/read";

function textOutput(result: AgentToolResult<ReadToolDetails>): string {
	return result.content
		.filter(content => content.type === "text")
		.map(content => content.text)
		.join("\n");
}

function createSession(cwd: string): ToolSession {
	const sessionDir = path.join(cwd, "session");
	let artifactCounter = 0;
	return {
		cwd,
		hasUI: false,
		getSessionFile: () => path.join(cwd, "session.jsonl"),
		getSessionSpawns: () => "*",
		getArtifactsDir: () => sessionDir,
		allocateOutputArtifact: async (toolType: string) => {
			await fs.mkdir(sessionDir, { recursive: true });
			const id = `artifact-${++artifactCounter}`;
			return { id, path: path.join(sessionDir, `${id}.${toolType}.log`) };
		},
		settings: Settings.isolated(),
	} as unknown as ToolSession;
}

// Reading a generated file is legitimate, but the agent should be steered away from paginating
// through it. The read tool surfaces a non-fatal notice (it must NOT throw the way edit guards do).
describe("read auto-generated notice", () => {
	let tmpDir: string;

	beforeEach(async () => {
		tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), "read-autogen-test-"));
	});

	afterEach(async () => {
		await fs.rm(tmpDir, { recursive: true, force: true });
	});

	it("prepends a notice when the header carries a generated marker", async () => {
		const fixture = path.join(tmpDir, "header-marked.ts");
		await fs.writeFile(fixture, "// @generated by protoc\nexport const x = 1;\nexport const y = 2;\n");

		const tool = new ReadTool(createSession(tmpDir));
		const result = await tool.execute("read-autogen-header", { path: fixture });
		const text = textOutput(result);

		expect(text).toContain("Auto-generated file");
		expect(text).toContain("@generated");
		// Still returns the actual content — the notice is additive, not a block.
		expect(text).toContain("export const x = 1;");
	});

	it("prepends a notice for generated filename patterns (e.g. *.pb.ts)", async () => {
		const fixture = path.join(tmpDir, "service.pb.ts");
		await fs.writeFile(fixture, "export const proto = true;\n");

		const tool = new ReadTool(createSession(tmpDir));
		const result = await tool.execute("read-autogen-name", { path: fixture });
		const text = textOutput(result);

		expect(text).toContain("Auto-generated file");
		expect(text).toContain("export const proto = true;");
	});

	it("does not add a notice for ordinary hand-written files", async () => {
		const fixture = path.join(tmpDir, "ordinary.ts");
		await fs.writeFile(fixture, "// a normal comment\nexport const z = 3;\n");

		const tool = new ReadTool(createSession(tmpDir));
		const result = await tool.execute("read-ordinary", { path: fixture });
		const text = textOutput(result);

		expect(text).not.toContain("Auto-generated file");
		expect(text).toContain("export const z = 3;");
	});
});
